import { runScript } from '../../sdk/runner';

export default async function script(ctx: any) {
  const { bot, sdk, log } = ctx;
  await bot.skipTutorial();
  await bot.equipItem('Bronze pickaxe');
  log("Walking to Varrock SE mine...");
  await bot.walkTo(3285, 3365, 5);
  log("Arrived. Scanning rocks...");
  const locs = sdk.scanNearbyLocs(15).filter((l: any) => /rocks?/i.test(l.name) && l.optionsWithIndex?.some((o:any) => /mine/i.test(o.text)));
  const ids = Array.from(new Set(locs.map((l:any) => l.id)));
  log(`Found rocks with IDs: ${ids.join(', ')}`);

  // Try mining the first rock
  if (locs.length > 0) {
    const rock = locs[0];
    log(`Attempting to mine rock ID ${rock.id} at ${rock.x}, ${rock.z}`);
    const res = await bot.interactLoc(rock, /mine/i);
    log(`Result: ${JSON.stringify(res)}`);
    // wait a bit to see if xp drops
    await sdk.sendWait(5);
  }

  return { ids, locs: locs.slice(0, 3) };
}

