  log('Walking to Port Sarim Fishing Shop...');
  await bot.walkTo(3014, 3223);
  log('Arrived! Interacting with Gerrant...');

  const gerrant = sdk.findNearbyNpc(/Gerrant/i);
  if (gerrant) {
    const tradeOpt = gerrant.optionsWithIndex.find(o => /trade/i.test(o.text));
