      const shopItems = sdk.getState().shop?.items;
      if (shopItems) {
        log('Shop items:');
        shopItems.forEach(i => log(`${i.name} - Price: ${i.price}`));
      } else {
        log('Shop not open!');
      }
    }
  }
  return { done: true };
});

